<div class="d-flex"><?php require_once __DIR__.'/../includes/sidebar.php'; ?><main class="container-fluid py-4"><div class="d-flex justify-content-between mb-3"><h1 class="h4"><?php echo (($user['role']??'')==='CLIENT')?'Mes paiements':'Paiements'; ?></h1><?php if(($user['role']??'')==='EXPERT'): ?><a class="btn btn-primary" href="/MNS_CORPORATE/frontend/views/payments/create.php">Nouveau paiement</a><?php endif; ?></div><div class="table-responsive bg-white border rounded"><table class="table table-hover"><thead><tr><th>Facture</th><th>Client</th><th>Date</th><th>Montant</th><th>Moyen</th><th>Reference</th><th>Recu par</th></tr></thead><tbody><?php foreach($payments as $p): ?><tr><td><?php echo e($p['invoice_number']); ?></td><td><?php echo e($p['company_name']); ?></td><td><?php echo e($p['payment_date']); ?></td><td><?php echo e((string)$p['amount']); ?></td><td><?php echo e($p['payment_method']); ?></td><td><?php echo e($p['reference_number']); ?></td><td><?php echo e($p['receiver_name']); ?></td></tr><?php endforeach; ?><?php if(($payments??[])===[]): ?><tr><td colspan="7" class="text-center text-muted py-4">Aucun paiement.</td></tr><?php endif; ?></tbody></table></div></main></div><?php require_once __DIR__.'/../includes/footer.php'; ?>
